use soroban_sdk::{contract, contractimpl, contracttype, Address, Env};

#[contracttype]
pub enum Role { Admin, Moderator, User }

#[contractimpl]
impl RoleContract {
    // WEAK: grant_role with only basic require_auth (no hierarchy check)
    pub fn grant_role(env: Env, caller: Address, target: Address, role: Role) {
        caller.require_auth();
        env.storage().instance().set(&target, &role);
    }

    // WEAK: assign_role with no auth at all
    pub fn assign_role(env: Env, target: Address, role: Role) {
        env.storage().instance().set(&target, &role);
    }

    // SAFE: promote with admin.require_auth + assert_admin (proper hierarchy)
    pub fn safe_promote(env: Env, admin: Address, target: Address, role: Role) {
        admin.require_auth();
        assert_admin(&env, &admin);
        env.storage().instance().set(&target, &role);
    }

    // WEAK: set_role with only require_auth
    pub fn set_role(env: Env, caller: Address, target: Address, role: Role) {
        caller.require_auth();
        env.storage().instance().set(&target, &role);
    }

    // SAFE: add_admin with only_admin guard
    pub fn add_admin(env: Env, caller: Address, new_admin: Address) {
        only_admin(&env, &caller);
        env.storage().instance().set(&new_admin, &Role::Admin);
    }

    // SAFE: make_admin with admin.require_auth
    pub fn make_admin(env: Env, admin: Address, target: Address) {
        admin.require_auth();
        require_role(&env, &admin, Role::Admin);
        env.storage().instance().set(&target, &Role::Admin);
    }

    // WEAK: add_role with no auth at all
    pub fn add_role(env: Env, target: Address, role: Role) {
        env.storage().instance().set(&target, &role);
    }

    // WEAK: escalate_role with basic require_auth
    pub fn escalate_role(env: Env, caller: Address, target: Address, role: Role) {
        caller.require_auth();
        env.storage().instance().set(&target, &role);
    }

    // SAFE: set_admin with require_auth and is_admin check
    pub fn set_admin(env: Env, admin: Address, new_admin: Address) {
        admin.require_auth();
        if !is_admin(&env, &admin) { panic!("not admin") };
        env.storage().instance().set(&Symbol::new(&env, "admin"), &new_admin);
    }
}
